  tests_passed: testsPassed,
  test_rounds: testRound,
  e2e_passed: e2ePassed,
  e2e_rounds: e2eRound,
  final_check_passed: finalPassed,
  final_check_gaps_found: frozenGaps.length,
  passed: testsPassed && e2ePassed && finalPassed,
}

